    rows = ""
    for y in GLD_YEARLY:
        m, b = y["main"], y["bh"]
        d = (m - b) if (m is not None and b is not None) else None
        dc = "pos" if (d is not None and d >= 0) else "neg"
        rows += (f'<tr><td>{y["year"]}</td>'
                 f'<td class="num">{fmt_pct(m*100,1,True) if m is not None else "—"}</td>'
                 f'<td class="num">{fmt_pct(b*100,1,True) if b is not None else "—"}</td>'
                 f'<td class="num {dc}">{fmt_pct(d*100,1,True) if d is not None else "—"}</td></tr>')
